sys_script_email.script:
(function runMailScript(/* GlideRecord */ current, /* TemplatePrinter */ template,
          /* Optional EmailOutbound */ email, /* Optional GlideRecord */ email_action,
          /* Optional GlideRecord */ event) {

	var objectiveLabel = current.u_objective.getLabel();
	var newSubject = gs.getMessage("{0} Updated for {1}", [objectiveLabel, current.getDisplayValue('u_top_task.task_name')]);

	var task_link = new x_153465_discovert.tasker_User_Form_Preferences().getEmailLink(current);

	var gr_user = new GlideRecord('sys_user');
	var task_owner_html = '<b>' + current.getDisplayValue('u_top_task.u_task_requester') + '</b>';
	if(gr_user.get(current.u_top_task.u_task_requester)){
		task_owner_html = '<a href="mailto:' + gr_user.email + '">' + current.getDisplayValue('u_top_task.u_task_requester') + '</a>';
	}

	// ----------------------------------------------------
	// Setting Subject here
	// ----------------------------------------------------
	email.setSubject(newSubject);

	// ----------------------------------------------------
	// Template Start
	// ----------------------------------------------------
	template.print(gs.getMessage("Hi, "));
	template.print("<br/><br/>");

	template.print(gs.getMessage("{0} has been updated for {1}.  Any task you are working in this tree has also been updated.", [objectiveLabel, task_link]));

	template.print("<br/><br/>");
	template.print(gs.getMessage("<b>Previous {0}</b>: <br/>{1}", 
					[objectiveLabel, event.parm2]));

	template.print("<br/><br/>");
	template.print(gs.getMessage("<b>New {0}</b>: <br/>{1}", 
					[objectiveLabel, current.u_objective]));

	template.print("<br/><br/>");
	template.print(gs.getMessage("For additional clarification, please contact the Task Owner: {0}.",
					[task_owner_html]));
	// ----------------------------------------------------
	// Template End
	// ----------------------------------------------------
})(current, template, email, email_action, event);
